import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Meters","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/finance/meters.md","filePath":"guide/admin/finance/meters.md","lastUpdated":1778862269000}'),n={name:"guide/admin/finance/meters.md"};function d(s,t,i,l,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="meters" tabindex="-1">Meters <a class="header-anchor" href="#meters" aria-label="Permalink to &quot;Meters&quot;">​</a></h1><p>The <strong>Finance → Meters</strong> page lists every meter and lets you create custom ones. See <a href="./../../concepts/plans-and-meters">Plans &amp; Meters</a> for what meters are conceptually.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Header with an <strong>Add Meter</strong> button. Toolbar with search. Table.</p><h2 id="columns" tabindex="-1">Columns <a class="header-anchor" href="#columns" aria-label="Permalink to &quot;Columns&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Column</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Monospace internal key (e.g. <code>api_calls</code>).</td></tr><tr><td><strong>Display Name</strong></td><td>Customer-facing label.</td></tr><tr><td><strong>Unit</strong></td><td>count / gb / mb / kb.</td></tr><tr><td><strong>Mode</strong></td><td>Snapshot / Delta / Distinct badge.</td></tr><tr><td><strong>Description</strong></td><td>Free text, or <code>—</code>.</td></tr><tr><td><strong>Type</strong></td><td>Built-in / Custom badge.</td></tr><tr><td><strong>Created</strong></td><td>Date.</td></tr></tbody></table><h2 id="adding-a-meter" tabindex="-1">Adding a meter <a class="header-anchor" href="#adding-a-meter" aria-label="Permalink to &quot;Adding a meter&quot;">​</a></h2><p>Click <strong>Add Meter</strong>.</p><table tabindex="0"><thead><tr><th>Field</th><th>Notes</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>Snake_case internal key. Used in API payloads, webhooks, and CSV exports.</td></tr><tr><td><strong>Display Name</strong></td><td>What customers see in invoices and dashboards.</td></tr><tr><td><strong>Unit</strong></td><td>count / gb / mb / kb.</td></tr><tr><td><strong>Aggregation Mode</strong></td><td>See below.</td></tr><tr><td><strong>Description</strong></td><td>Optional.</td></tr></tbody></table><p>Click <strong>Create Meter</strong>.</p><h2 id="aggregation-modes" tabindex="-1">Aggregation modes <a class="header-anchor" href="#aggregation-modes" aria-label="Permalink to &quot;Aggregation modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mode</th><th>Behaviour</th><th>Use for</th></tr></thead><tbody><tr><td><strong>Snapshot</strong></td><td>The latest value in the period wins.</td><td>Gauges — &quot;active users right now&quot;, &quot;storage used right now&quot;.</td></tr><tr><td><strong>Delta</strong></td><td>Values accumulate over the period.</td><td>Counters — &quot;API calls this month&quot;, &quot;events emitted&quot;.</td></tr><tr><td><strong>Distinct</strong></td><td>Count unique IDs over the period.</td><td>Session-like — &quot;distinct users this month&quot;.</td></tr></tbody></table><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Built-in meters cannot be deleted. They are part of the platform and may be referenced by built-in plans.</li><li>Custom meters can be deleted only if they are not referenced by any plan. Plan reference = &quot;in use&quot; — remove from plans first.</li><li>Meters are global. Once defined, every plan can reference them with its own included quantity and overage price.</li><li>Snake_case enforcement on the name is deliberate — meter names show up in webhooks and CSV exports, so they need to be machine-friendly.</li></ul>',14)])])}const m=e(n,[["render",d]]);export{u as __pageData,m as default};
